#!/usr/bin/env node\n\n/**\n * GitHub Branch Protection Setup Script\n * \n * This script automates the setup of GitHub repository rulesets using the GitHub API.\n * It implements enterprise-grade branch protection following 2025 best practices.\n * \n * Usage:\n *   # Set GitHub token\n *   export GITHUB_TOKEN=\"your_personal_access_token\"\n *   \n *   # Run the setup\n *   node setup-branch-protection.js [owner] [repo]\n *   \n *   # Or with npm script\n *   npm run setup:branch-protection\n * \n * Requirements:\n *   - GitHub Personal Access Token with 'repo' scope\n *   - Admin access to the target repository\n *   - Node.js 18+ with fetch support\n */\n\nconst fs = require('fs');\nconst path = require('path');\n\n// Configuration\nconst CONFIG_FILE = path.join(__dirname, 'rulesets-config.json');\nconst GITHUB_API_BASE = 'https://api.github.com';\n\n// Colors for console output\nconst colors = {\n  reset: '\\x1b[0m',\n  bright: '\\x1b[1m',\n  red: '\\x1b[31m',\n  green: '\\x1b[32m',\n  yellow: '\\x1b[33m',\n  blue: '\\x1b[34m',\n  magenta: '\\x1b[35m',\n  cyan: '\\x1b[36m'\n};\n\nfunction log(message, color = 'reset') {\n  console.log(`${colors[color]}${message}${colors.reset}`);\n}\n\nclass GitHubBranchProtectionSetup {\n  constructor(token, owner, repo) {\n    this.token = token;\n    this.owner = owner;\n    this.repo = repo;\n    this.baseUrl = `${GITHUB_API_BASE}/repos/${owner}/${repo}`;\n    \n    if (!token) {\n      throw new Error('GitHub token is required. Set GITHUB_TOKEN environment variable.');\n    }\n  }\n\n  async makeRequest(url, method = 'GET', body = null) {\n    const options = {\n      method,\n      headers: {\n        'Authorization': `token ${this.token}`,\n        'Accept': 'application/vnd.github+json',\n        'X-GitHub-Api-Version': '2022-11-28',\n        'User-Agent': 'TraffBoard-Branch-Protection-Setup/1.0'\n      }\n    };\n\n    if (body) {\n      options.headers['Content-Type'] = 'application/json';\n      options.body = JSON.stringify(body);\n    }\n\n    const response = await fetch(url, options);\n    \n    if (!response.ok) {\n      const errorBody = await response.text();\n      throw new Error(`GitHub API request failed: ${response.status} ${response.statusText}\\n${errorBody}`);\n    }\n\n    return response.json();\n  }\n\n  async loadConfig() {\n    try {\n      const configData = fs.readFileSync(CONFIG_FILE, 'utf8');\n      return JSON.parse(configData);\n    } catch (error) {\n      throw new Error(`Failed to load configuration from ${CONFIG_FILE}: ${error.message}`);\n    }\n  }\n\n  async verifyRepository() {\n    log('🔍 Verifying repository access...', 'blue');\n    \n    try {\n      const repo = await this.makeRequest(this.baseUrl);\n      log(`✅ Repository verified: ${repo.full_name}`, 'green');\n      \n      // Check permissions\n      if (!repo.permissions.admin) {\n        log('⚠️  Warning: Admin permissions may be required for some operations', 'yellow');\n      }\n      \n      return repo;\n    } catch (error) {\n      throw new Error(`Failed to verify repository: ${error.message}`);\n    }\n  }\n\n  async createRuleset(rulesetConfig) {\n    log(`📋 Creating ruleset: ${rulesetConfig.name}`, 'cyan');\n    \n    try {\n      const ruleset = await this.makeRequest(\n        `${this.baseUrl}/rulesets`,\n        'POST',\n        rulesetConfig\n      );\n      \n      log(`✅ Created ruleset: ${ruleset.name} (ID: ${ruleset.id})`, 'green');\n      return ruleset;\n    } catch (error) {\n      log(`❌ Failed to create ruleset ${rulesetConfig.name}: ${error.message}`, 'red');\n      throw error;\n    }\n  }\n\n  async updateRepositorySettings(settings) {\n    log('⚙️  Updating repository settings...', 'blue');\n    \n    try {\n      const updatedRepo = await this.makeRequest(\n        this.baseUrl,\n        'PATCH',\n        settings\n      );\n      \n      log('✅ Repository settings updated', 'green');\n      return updatedRepo;\n    } catch (error) {\n      log(`⚠️  Failed to update some repository settings: ${error.message}`, 'yellow');\n      // Non-fatal, continue with setup\n      return null;\n    }\n  }\n\n  async configureSecuritySettings(settings) {\n    log('🔒 Configuring security settings...', 'blue');\n    \n    const securityEndpoints = {\n      vulnerability_alerts: '/vulnerability-alerts',\n      automated_security_fixes: '/automated-security-fixes',\n      secret_scanning: '/secret-scanning',\n      push_protection: '/secret-scanning/push-protection'\n    };\n\n    const results = {};\n\n    for (const [setting, enabled] of Object.entries(settings)) {\n      if (securityEndpoints[setting] && enabled) {\n        try {\n          await this.makeRequest(\n            `${this.baseUrl}${securityEndpoints[setting]}`,\n            'PUT'\n          );\n          log(`✅ Enabled ${setting}`, 'green');\n          results[setting] = 'enabled';\n        } catch (error) {\n          log(`⚠️  Could not enable ${setting}: ${error.message}`, 'yellow');\n          results[setting] = 'failed';\n        }\n      }\n    }\n\n    return results;\n  }\n\n  async listExistingRulesets() {\n    try {\n      const rulesets = await this.makeRequest(`${this.baseUrl}/rulesets`);\n      return rulesets;\n    } catch (error) {\n      log(`⚠️  Could not list existing rulesets: ${error.message}`, 'yellow');\n      return [];\n    }\n  }\n\n  async deleteRuleset(rulesetId) {\n    try {\n      await this.makeRequest(`${this.baseUrl}/rulesets/${rulesetId}`, 'DELETE');\n      log(`🗑️  Deleted existing ruleset (ID: ${rulesetId})`, 'yellow');\n    } catch (error) {\n      log(`⚠️  Could not delete ruleset ${rulesetId}: ${error.message}`, 'yellow');\n    }\n  }\n\n  async setup(options = {}) {\n    const { force = false, dryRun = false } = options;\n    \n    log('🚀 Starting GitHub Branch Protection Setup...', 'bright');\n    log(`📂 Repository: ${this.owner}/${this.repo}`, 'blue');\n    \n    if (dryRun) {\n      log('🧪 DRY RUN MODE - No changes will be made', 'yellow');\n    }\n\n    try {\n      // Step 1: Verify repository access\n      const repo = await this.verifyRepository();\n      \n      // Step 2: Load configuration\n      log('📄 Loading branch protection configuration...', 'blue');\n      const config = await this.loadConfig();\n      \n      // Step 3: Handle existing rulesets\n      const existingRulesets = await this.listExistingRulesets();\n      if (existingRulesets.length > 0) {\n        log(`Found ${existingRulesets.length} existing rulesets`, 'yellow');\n        \n        if (force && !dryRun) {\n          log('🔄 Force mode enabled - removing existing rulesets...', 'yellow');\n          for (const ruleset of existingRulesets) {\n            await this.deleteRuleset(ruleset.id);\n          }\n        } else if (!force) {\n          log('ℹ️  Use --force to replace existing rulesets', 'blue');\n        }\n      }\n      \n      if (dryRun) {\n        log('\\n📋 DRY RUN SUMMARY:', 'bright');\n        log(`Would create ${config.rulesets.length} rulesets:`, 'blue');\n        config.rulesets.forEach(ruleset => {\n          log(`  - ${ruleset.name}`, 'cyan');\n        });\n        return;\n      }\n      \n      // Step 4: Create rulesets\n      log('\\n📋 Creating branch protection rulesets...', 'bright');\n      const createdRulesets = [];\n      \n      for (const rulesetConfig of config.rulesets) {\n        try {\n          const ruleset = await this.createRuleset(rulesetConfig);\n          createdRulesets.push(ruleset);\n        } catch (error) {\n          log(`⚠️  Continuing with remaining rulesets...`, 'yellow');\n        }\n      }\n      \n      // Step 5: Update repository settings\n      if (config.repository_settings) {\n        await this.updateRepositorySettings(config.repository_settings);\n      }\n      \n      // Step 6: Configure security settings\n      if (config.security_settings) {\n        await this.configureSecuritySettings(config.security_settings);\n      }\n      \n      // Step 7: Summary\n      log('\\n🎉 Branch Protection Setup Complete!', 'bright');\n      log(`✅ Created ${createdRulesets.length} rulesets`, 'green');\n      log(`📂 Repository: https://github.com/${this.owner}/${this.repo}/settings/rules`, 'blue');\n      \n      return {\n        success: true,\n        rulesets: createdRulesets,\n        repository: repo\n      };\n      \n    } catch (error) {\n      log(`\\n❌ Setup failed: ${error.message}`, 'red');\n      throw error;\n    }\n  }\n}\n\n// CLI Interface\nasync function main() {\n  const args = process.argv.slice(2);\n  \n  // Parse arguments\n  const flags = {\n    force: args.includes('--force'),\n    dryRun: args.includes('--dry-run'),\n    help: args.includes('--help') || args.includes('-h')\n  };\n  \n  if (flags.help) {\n    console.log(`\n🛡️  GitHub Branch Protection Setup\n\nUsage:\n  node setup-branch-protection.js [owner] [repo] [options]\n\nOptions:\n  --force     Replace existing rulesets\n  --dry-run   Show what would be done without making changes\n  --help, -h  Show this help message\n\nEnvironment Variables:\n  GITHUB_TOKEN  Personal access token with 'repo' scope (required)\n  \nExamples:\n  node setup-branch-protection.js myorg myrepo\n  node setup-branch-protection.js myorg myrepo --force\n  node setup-branch-protection.js myorg myrepo --dry-run\n`);\n    process.exit(0);\n  }\n  \n  // Get repository info\n  const nonFlagArgs = args.filter(arg => !arg.startsWith('--'));\n  let owner, repo;\n  \n  if (nonFlagArgs.length >= 2) {\n    [owner, repo] = nonFlagArgs;\n  } else {\n    // Try to detect from git remote\n    try {\n      const { execSync } = require('child_process');\n      const remote = execSync('git remote get-url origin', { encoding: 'utf8' }).trim();\n      const match = remote.match(/github\\.com[:/]([^/]+)\\/([^/.]+)/);\n      if (match) {\n        [, owner, repo] = match;\n        log(`🔍 Detected repository from git remote: ${owner}/${repo}`, 'blue');\n      }\n    } catch (error) {\n      // Ignore git detection errors\n    }\n  }\n  \n  if (!owner || !repo) {\n    log('❌ Repository owner and name are required', 'red');\n    log('Usage: node setup-branch-protection.js [owner] [repo]', 'yellow');\n    process.exit(1);\n  }\n  \n  const token = process.env.GITHUB_TOKEN;\n  if (!token) {\n    log('❌ GITHUB_TOKEN environment variable is required', 'red');\n    log('Generate a token at: https://github.com/settings/tokens', 'blue');\n    process.exit(1);\n  }\n  \n  try {\n    const setup = new GitHubBranchProtectionSetup(token, owner, repo);\n    await setup.setup(flags);\n  } catch (error) {\n    log(`\\n💥 Fatal error: ${error.message}`, 'red');\n    process.exit(1);\n  }\n}\n\n// Run if called directly\nif (require.main === module) {\n  main().catch(error => {\n    console.error('Unhandled error:', error);\n    process.exit(1);\n  });\n}\n\nmodule.exports = GitHubBranchProtectionSetup;
